parameters.jsCode:
const raw = $input.item.json.message.content.replace(/```json|```/g, '').trim();
const parsed = JSON.parse(raw);
return {
  task_type: parsed.task_type || 'GENERATE',
  language: parsed.language || $('Set Task Config').item.json.language,
  summary: parsed.summary || 'AI Coding Task',
  original_task: $input.item.json.message.content
};

